CREATE TABLE IF NOT EXISTS gazettes (id VARCHAR(36) PRIMARY KEY, college_id VARCHAR(64) NOT NULL, exam_id VARCHAR(36) NOT NULL, scope_type VARCHAR(32) NOT NULL, scope_id VARCHAR(64) NOT NULL DEFAULT '', status VARCHAR(32) NOT NULL DEFAULT 'GENERATED', title VARCHAR(180) NOT NULL, summary_json TEXT NOT NULL, rows_json TEXT NOT NULL, generated_by VARCHAR(64) NOT NULL, generated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT uq_gazette_scope UNIQUE (college_id, exam_id, scope_type, scope_id));
CREATE INDEX IF NOT EXISTS ix_gazettes_college_exam ON gazettes (college_id, exam_id, scope_type);
